UPDATE sys_menu
menu_name = #{menuName}, menu_code = #{menuCode}, menu_type = #{menuType}, path = #{path}, component = #{component}, perms = #{perms}, icon = #{icon}, sort_order = #{sortOrder}, visible = #{visible}, status = #{status}, remark = #{remark},
WHERE id = #{id}

mapper.select:
SELECT 
FROM sys_menu


        AND (menu_name LIKE CONCAT('%', #{filter.keyword}, '%')
        OR menu_code LIKE CONCAT('%', #{filter.keyword}, '%'))


        AND menu_type = #{filter.menuType}


        AND visible = #{filter.visible}


        AND status = #{filter.status}


        AND parent_id = #{filter.parentId}


ORDER BY

    sort_order
    create_time
    id


    DESC
    ASC

LIMIT #{filter.size} OFFSET #{filter.offset}

SELECT COUNT(*)
FROM sys_menu


        AND (menu_name LIKE CONCAT('%', #{filter.keyword}, '%')
        OR menu_code LIKE CONCAT('%', #{filter.keyword}, '%'))


        AND menu_type = #{filter.menuType}


        AND visible = #{filter.visible}


        AND status = #{filter.status}


        AND parent_id = #{filter.parentId}
